using System;
using System.Data.SqlClient;

public class LoginValidator
{
    public bool ValidateLogin(string username, string password)
    {
        string connectionString = "Your SQL Server connection string";
        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            try
            {
                connection.Open();
                string query = "SELECT COUNT(*) FROM Users WHERE Username=@username AND Password=HASHBYTES('SHA2_256', @password)";
                SqlCommand command = new SqlCommand(query, connection);
                command.Parameters.AddWithValue("@username", username);
                command.Parameters.AddWithValue("@password", password);

                int result = (int)command.ExecuteScalar();
                return result > 0;
            }
            catch (Exception ex)
            {
                Console.WriteLine("Error validating login: " + ex.Message);
                return false;
            }
        }
    }
